if (msg.payload.fix === 0) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'waiting for fix (' + msg.payload.satellites + ' sats)' });
    return null;
}
node.status({ fill: 'green', shape: 'dot', text: 'fix: ' + msg.payload.fix });
msg.payload = msg.payload.lat.toFixed(6) + ',' + msg.payload.lon.toFixed(6);
return msg;
